def upgrade() -> None:
    # Idempotent: safe to re-run if migration was interrupted
    conn = op.get_bind()
    inspector = sa.inspect(conn)
    if "tool_events" not in inspector.get_table_names():
        op.create_table(
            "tool_events",
            sa.Column("id", sa.BigInteger(), primary_key=True),
            sa.Column("run_id", sa.UUID(), nullable=False),
        )
    if not any(
        ix["name"] == "ix_tool_events_run_id"
        for ix in inspector.get_indexes("tool_events")
    ):
        op.create_index("ix_tool_events_run_id", "tool_events", ["run_id"])

-- Grant append-only access to the application role
GRANT INSERT ON tool_events TO app_user;
REVOKE UPDATE, DELETE ON tool_events FROM app_user;

-- For extra protection, create a row-level security policy
ALTER TABLE tool_events ENABLE ROW LEVEL SECURITY;
CREATE POLICY no_delete ON tool_events FOR DELETE USING (FALSE);
